steps:
For each sample write a command to the file that will be used to read a MEGAN file and output taxonomic classifications. Taxonomic classifications will be made at the Super Kingdom, Phylum, Genera, and Species levels. for file in $(ls *.fa); doprintf 'open file='Ray/MEGAN/output/${file/_Contigs_with_format.fa/.rma}';
collapse rank=SuperKingdom;
select nodes=all;
export what=DSV format=taxonpath_count separator=tab counts=summarized file='Ray/MEGAN/output/${file/_Contigs_with_format.fa/_super_kingdom.txt}';
select nodes=none;
uncollapse nodes=all;
select rank=Phylum;
export what=DSV format=taxonpath_count separator=tab counts=summarized file='Ray/MEGAN/output/${file/_Contigs_with_format.fa/_phyla.txt}';
select nodes=none;
select rank=Genus;
export what=DSV format=taxonpath_count separator=tab counts=summarized file='Ray/MEGAN/output/${file/_Contigs_with_format.fa/_genus.txt}';
select nodes=none;
select rank=Species;
export what=DSV format=taxonpath_count separator=tab counts=summarized file='Ray/MEGAN/output/${file/_Contigs_with_format.fa/_species.txt}';
'>> Ray/MEGAN/MEGAN_taxonomy_commands.txtdone for file in $(ls *.fa); do printf &#39;open file=&#39;Ray/MEGAN/output/${file/_Contigs_with_format.fa/.rma}&#39;;
collapse rank=SuperKingdom;
select nodes=all;
export what=DSV format=taxonpath_count separator=tab counts=summarized file=&#39;Ray/MEGAN/output/${file/_Contigs_with_format.fa/_super_kingdom.txt}&#39;;
select nodes=none;
uncollapse nodes=all;
select rank=Phylum;
export what=DSV format=taxonpath_count separator=tab counts=summarized file=&#39;Ray/MEGAN/output/${file/_Contigs_with_format.fa/_phyla.txt}&#39;;
select nodes=none;
select rank=Genus;
export what=DSV format=taxonpath_count separator=tab counts=summarized file=&#39;Ray/MEGAN/output/${file/_Contigs_with_format.fa/_genus.txt}&#39;;
select nodes=none;
select rank=Species;
export what=DSV format=taxonpath_count separator=tab counts=summarized file=&#39;Ray/MEGAN/output/${file/_Contigs_with_format.fa/_species.txt}&#39;;
&#39;&gt;&gt; Ray/MEGAN/MEGAN_taxonomy_commands.txt done

Add a line to the end of the command files that tells MEGAN to exit. printf 'quit;
' >> ./Ray/MEGAN/MEGAN_file_generation_commands.txtprintf 'quit;
' >> ./Ray/MEGAN/MEGAN_taxonomy_commands.txt printf &#39;quit;
&#39; &gt;&gt; ./Ray/MEGAN/MEGAN_file_generation_commands.txt printf &#39;quit;
&#39; &gt;&gt; ./Ray/MEGAN/MEGAN_taxonomy_commands.txt
